pub fn pattern_from_os(pattern: &OsStr) -> Result<&str, InvalidPatternError> {
    pattern.to_str().ok_or_else(|| {
        let valid_up_to = pattern
            .to_string_lossy()
            .find('\u{FFFD}')
            .expect("a Unicode replacement codepoint for invalid UTF-8");
        InvalidPatternError { original: escape_os(pattern), valid_up_to }
    })
}

pub fn insert_tail(&self, key: u64, data: T, weight: usize) -> bool {
    let shard = get_shard(key, N);
    if self.units[shard].write().insert_tail(key, data, weight) {
        self.weight.fetch_add(weight, Ordering::Relaxed);
        self.incr_count(shard);
        true
    } else {
        false
    }
}

fn new_node(&mut self, data: u64) -> Index {
    if let Some(index) = self.free.pop() {
        // have a free node, update its payload and return its index
        self.nodes[index].data = data;
        index
    } else {
        // create a new node
        self.nodes.new_node(data)
    }
}

pub fn is_compatible_with(&self, current_version: &str) -> bool {
    let current_version =
        Version::parse(current_version).expect("bat follows semantic versioning");
    let stored_version = self
        .bat_version
        .as_ref()
        .and_then(|ver| Version::parse(ver).ok());

    if let Some(stored_version) = stored_version {
        current_version.major == stored_version.major
            && current_version.minor == stored_version.minor
    } else {
        false
    }
}

fn call(&self, req: ServiceRequest) -> Self::Future {
    let handlers = Rc::clone(&self.handlers);
    let default_client = self.default_client.clone();
    let default_server = self.default_server.clone();
    let fut = self.service.call(req);
    ErrorHandlersFuture::ServiceFuture {
        fut,
        default_client,
        default_server,
        handlers,
    }
}

pub fn freeze(self) -> Result<FrozenClientRequest, FreezeRequestError> {
    let slf = self.prep_for_sending()?;

    let request = FrozenClientRequest {
        head: Rc::new(slf.head),
        addr: slf.addr,
        response_decompress: slf.response_decompress,
        timeout: slf.timeout,
        config: slf.config,
    };

    Ok(request)
}

fn count_lines(&mut self, buf: &[u8], upto: usize) {
    if let Some(ref mut line_number) = self.line_number {
        if self.last_line_counted >= upto {
            return;
        }
        let slice = &buf[self.last_line_counted..upto];
        let count = lines::count(slice, self.config.line_term.as_byte());
        *line_number += count;
        self.last_line_counted = upto;
    }
}

fn search_decompress(&mut self, path: &Path) -> io::Result<SearchResult> {
    let Some(ref decomp_builder) = self.decomp_builder else {
        return self.search_path(path);
    };
    let mut rdr = decomp_builder.build(path)?;
    let result = self.search_reader(path, &mut rdr);
    let close_result = rdr.close();
    let search_result = result?;
    close_result?;
    Ok(search_result)
}

fn next(&mut self) -> Option<Self::Item> {
    let haystack = self.haystack?;
    if let Some((first, second)) = haystack.split_once(self.needle) {
        if !haystack.is_empty() {
            debug_assert_ne!(haystack, second);
        }
        self.haystack = Some(second);
        Some(first)
    } else {
        self.haystack = None;
        Some(haystack)
    }
}

pub(crate) unsafe fn disconnect_receivers(&self) -> bool {
    let tail = self.tail.fetch_or(self.mark_bit, Ordering::SeqCst);
    let disconnected = if tail & self.mark_bit == 0 {
        self.senders.disconnect();
        true
    } else {
        false
    };

    unsafe { self.discard_all_messages(tail) }
    disconnected
}

pub unsafe fn unprotected() -> &'static Guard {
    // An unprotected guard is just a `Guard` with its field `local` set to null.
    // We make a newtype over `Guard` because `Guard` isn't `Sync`, so can't be directly stored in
    // a `static`
    struct GuardWrapper(Guard);
    unsafe impl Sync for GuardWrapper {}
    static UNPROTECTED: GuardWrapper = GuardWrapper(Guard {
        local: core::ptr::null(),
    });
    &UNPROTECTED.0
}

pub(super) fn transition_to_complete(&self) -> Snapshot {
    const DELTA: usize = RUNNING | COMPLETE;

    let prev = Snapshot(self.val.fetch_xor(DELTA, AcqRel));
    assert!(prev.is_running());
    assert!(!prev.is_complete());

    Snapshot(prev.0 ^ DELTA)
}

pub fn calculate_dired(
    dired: &DiredOutput,
    output_display_len: usize,
    dfn_len: usize,
) -> (usize, usize) {
    let offset_from_previous_line = dired.line_offset;

    let start = output_display_len + offset_from_previous_line;
    let end = start + dfn_len;
    (start, end)
}

pub fn calculate_subdired(dired: &mut DiredOutput, path_len: usize) {
    let offset_from_previous_line = dired.line_offset + dired.padding;
    let start = offset_from_previous_line + DIRED_TRAILING_OFFSET;
    let end = start + path_len;
    dired.subdired_positions.push(BytePosition { start, end });
}

pub fn calculate_and_update_positions(
    dired: &mut DiredOutput,
    output_display_len: usize,
    dfn_len: usize,
    line_len: usize,
) {
    let (start, end) = calculate_dired(dired, output_display_len, dfn_len);
    update_positions(dired, start, end, line_len);
}

fn assert_successful_gzip_res_with_content_type<B>(res: &ServiceResponse<B>, ct: &str) {
    assert_successful_res_with_content_type(res, ct);
    assert_eq!(
        res.headers()
            .get(header::CONTENT_ENCODING)
            .expect("response should be gzip compressed"),
        "gzip",
    );
}

fn assert_successful_identity_res_with_content_type<B>(res: &ServiceResponse<B>, ct: &str) {
    assert_successful_res_with_content_type(res, ct);
    assert!(
        res.headers().get(header::CONTENT_ENCODING).is_none(),
        "response should not be compressed",
    );
}

fn from_f32(value: f32) -> Self {
    // Check that `value` is within range should be done before calling this method.
    // Just in case, this debug_assert should catch if we were forgetful.
    debug_assert!(
        (0.0..=MAX_QUALITY_FLOAT).contains(&value),
        "q value must be between 0.0 and 1.0"
    );

    Quality((value * MAX_QUALITY_INT as f32) as u16)
}

pub fn push(
    &mut self,
    rdef: ResourceDef,
    val: T,
    ctx: U,
) -> (&mut ResourceDef, &mut T, &mut U) {
    self.routes.push((rdef, val, ctx));
    #[allow(clippy::map_identity)] // map is used to distribute &mut-ness to tuple elements
    self.routes
        .last_mut()
        .map(|(rdef, val, ctx)| (rdef, val, ctx))
        .unwrap()
}

fn panic_after_wrap(replaced: &str, example: &str) -> ! {
    panic!(
        "Route middleware was already registered with `.wrap()`. \
         Calling `.{replaced}()` now would replace the wrapped service and silently drop middleware. \
         Call `.{replaced}()` before `.wrap()` (for example: `{example}`)."
    );
}

fn drop(&mut self) {
    // TODO: this can end up sending extraneous requests; see if there is a better way to handle
    if self
        .sender
        .send_request(http::Request::new(()), true)
        .is_err()
    {
        self.handle.abort();
    }
}

pub fn send_json(self, value: impl Serialize) -> SendClientRequest {
    if let Some(err) = self.err {
        return err.into();
    }

    RequestSender::Rc(self.req.head, Some(self.extra_headers)).send_json(
        self.req.addr,
        self.req.response_decompress,
        self.req.timeout,
        &self.req.config,
        value,
    )
}

pub fn send_form(self, value: impl Serialize) -> SendClientRequest {
    if let Some(err) = self.err {
        return err.into();
    }

    RequestSender::Rc(self.req.head, Some(self.extra_headers)).send_form(
        self.req.addr,
        self.req.response_decompress,
        self.req.timeout,
        &self.req.config,
        value,
    )
}

pub fn send(self) -> SendClientRequest {
    if let Some(err) = self.err {
        return err.into();
    }

    RequestSender::Rc(self.req.head, Some(self.extra_headers)).send(
        self.req.addr,
        self.req.response_decompress,
        self.req.timeout,
        &self.req.config,
    )
}

fn future_respond_to(self, _: &HttpRequest) -> Self::Future {
    // this is default builder for string response in both new and old responder trait.
    ready(Ok(HttpResponse::build(StatusCode::OK)
        .content_type("text/plain; charset=utf-8")
        .body(self.0)))
}

pub(crate) fn new(pattern: &str) -> RegexMatcher {
    let regex = RegexBuilder::new(pattern)
        .multi_line(true) // permits ^ and $ to match at \n boundaries
        .build()
        .unwrap();
    RegexMatcher { regex, line_term: None, every_line_is_candidate: false }
}

pub(crate) fn get(&self) -> (usize, usize) {
    let (mut before, mut after) =
        self.both.map(|lines| (lines, lines)).unwrap_or((0, 0));
    // --before and --after always override --context, regardless
    // of where they appear relative to each other.
    if let Some(lines) = self.before {
        before = lines;
    }
    if let Some(lines) = self.after {
        after = lines;
    }
    (before, after)
}

fn should_preprocess(&self, path: &Path) -> bool {
    if !self.config.preprocessor.is_some() {
        return false;
    }
    if self.config.preprocessor_globs.is_empty() {
        return true;
    }
    !self.config.preprocessor_globs.matched(path, false).is_ignore()
}

pub(crate) fn append_val(&mut self, val: AnyValue, raw_val: OsString) {
    // We assume there is always a group created before.
    self.vals.last_mut().expect(INTERNAL_ERROR_MSG).push(val);
    self.raw_vals
        .last_mut()
        .expect(INTERNAL_ERROR_MSG)
        .push(raw_val);
}
